mapper.update:
update sys_permission set parent_id = tmp.parent_id, level = tmp.level, sort = tmp.sort, update_time = NOW(), version = sys_permission.version + 1 from (values
(#{item.permissionId}::bigint, #{item.version}::int, #{item.parentId}::bigint, #{item.level}::int, #{item.sort}::int)
) as tmp(id, version, parent_id, level, sort) where sys_permission.permission_id = tmp.id and sys_permission.version = tmp.version
